    let diff = depth[a] - depth[b];
    for (let k = 0; k < LOG; k++)
        if ((diff >> k) & 1) a = up[k][a];
    if (a === b) return a;
    for (let k = LOG - 1; k >= 0; k--)
        if (up[k][a] !== up[k][b]) { a = up[k][a]; b = up[k][b]; }
    return up[0][a];
}

